mapper.update:
UPDATE tbl_shuttle_route
SET active_yn = 'N'
WHERE fk_hotel_id = #{hotelId}
  AND route_id = #{routeId}
  AND active_yn = 'Y'

UPDATE tbl_shuttle_timetable
SET active_yn = 'N'
WHERE fk_route_id IN (
  SELECT route_id
  FROM tbl_shuttle_route
  WHERE fk_hotel_id = #{hotelId}
    AND route_id = #{routeId}
)
  AND active_yn = 'Y'

UPDATE tbl_shuttle_block
SET active_yn = 'N'
WHERE fk_hotel_id = #{hotelId}
  AND shuttle_block_id = #{blockId}
  AND active_yn = 'Y'

mapper.delete:
DELETE FROM tbl_shuttle_booking
WHERE fk_hotel_id = #{hotelId}
  AND ride_date < #{cutoffDate}

DELETE FROM tbl_shuttle_slot_stock
WHERE fk_timetable_id IN (
  SELECT t.timetable_id
  FROM tbl_shuttle_timetable t
  JOIN tbl_shuttle_route r
    ON r.route_id = t.fk_route_id
  WHERE r.fk_hotel_id = #{hotelId}
)
  AND ride_date < #{cutoffDate}
